61	// Helper to wrap a 1D std::vector in a contiguous mdspan
62	template <typename T>
63	auto _as_mdspan(std::vector<T>& vec) {
64	    return std::mdspan<T, std::dextents<ptrdiff_t, 1>>(vec.data(), vec.size());
65	}
66	
67	template <typename T>
68	auto _as_mdspan(const std::vector<T>& vec) {
69	    return std::mdspan<const T, std::dextents<ptrdiff_t, 1>>(vec.data(), vec.size());
70	}
