72	/* gufunc kernels which use internal caches.
73	 *
74	 * Such caches live only during the course of a single call to the ufunc
75	 * in order to eliminate redundant calculations. This does not concern
76	 * user-facing caching across ufunc calls.
77	 *
78	 * In order for such caches to serve their purpose, the iteration order over the
79	 * course of the ufunc loops must be chosen so that elements (or core slices) of
80	 * the inputs that go into the cached computation vary most slowly and elements
81	 * of the inputs for which the cached result can be reused vary most quickly.
82	 * This can be accomplished by wrapping the gufunc with `_with_cache_optimization`
83	 * from ./_ufunc_tools.py. See the docstring of `_with_cache_optimization` for
84	 * more information.
85	 */
86	
87	template <typename T_1d>
88	struct _poisson_binom_pmf_kernel {
89	    using T = typename T_1d::value_type;
90	
91	    std::vector<T> dist;
92	    T* last_p_ptr = nullptr;
93	    T operator()(long long int k, T_1d p) {
94	        if (!last_p_ptr) {
95	            dist.resize(p.extent(0) + 1);
96	        }
97	        if (p.data_handle() != last_p_ptr) {
98	            /* If p is stepped through in the outer loops and k in the inner loops,
99	             * this will yield a cache hit for each inner iteration. The cache is
100	             * overwritten unconditionally whenever this steps to a new slice of p. */
101	            xsf::poisson_binom_pmf_all(p, _as_mdspan(dist));
102	            last_p_ptr = p.data_handle();
103	        }
104	
105	        return xsf::take_from_pmf(_as_mdspan(dist), k);
106	    }
107	};
108	
109	template <typename T_1d>
110	struct _poisson_binom_cdf_kernel {
111	    using T = typename T_1d::value_type;
112	
113	    std::vector<T> dist;
114	    T* last_p_ptr = nullptr;
115	    T operator()(long long int k, T_1d p) {
116	        if (!last_p_ptr) {
117	            dist.resize(p.extent(0) + 1);
118	        }
119	        if (p.data_handle() != last_p_ptr) {
120	            /* If p is stepped through in the outer loops and k in the inner loops,
121	            * this will yield a cache hit for each inner iteration. The cache is
122	            * overwritten unconditionally whenever this steps to a new slice of p. */
123	            xsf::poisson_binom_cdf_all(p, _as_mdspan(dist));
124	            last_p_ptr = p.data_handle();
125	        }
126	
127	        return xsf::take_from_discrete_cdf(_as_mdspan(dist), k);
128	    }
129	};
